import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const d={};function l(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<h3 id="查询索引" tabindex="-1"><a class="header-anchor" href="#查询索引"><span>查询索引</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.getIndexes()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>查询对应集合的索引情况</p><h3 id="创建索引" tabindex="-1"><a class="header-anchor" href="#创建索引"><span>创建索引</span></a></h3><ul><li>keys : 字段值</li><li>options : 可选项,设置索引的选项</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.createIndex(keys,options)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>创建索引时mongodb会自动根据索引值创建索引名称</p><table><thead><tr><th>选项</th><th>类型</th><th>作用</th></tr></thead><tbody><tr><td>background</td><td>Boolean</td><td>建索引过程会阻塞其它数据库操作，background可指定以后台方式创建索引，即增加“background&quot;可选参数。“background&quot;默认值为false.</td></tr><tr><td>unique</td><td>Boolean</td><td>建立的索引是否唯一。指定为true创建唯一索引。默认值为false.</td></tr><tr><td>name</td><td>string</td><td>索引的名称。如果未指定，MongoDB的通过连接索引的字段名和排序顺序生成一个索引名称。</td></tr><tr><td>dropDups</td><td>Boolean</td><td>3.0+版本已废弃。在建立唯一索引时是否删除重复记录，指定true创建唯一索引l。默认值为 fallse.</td></tr><tr><td>sparse</td><td>Boolean</td><td>对文档中不存在的字段数据不启用索引：这个参数需要特别注意，如sparseBoolean果设置为true的话，在索引字段中不会查询出不包含对应字段的文档。默认值为 fallse.</td></tr><tr><td>expireAfterSeconds</td><td>integer</td><td>指定一个以秒为单位的数值，完成TTL设定，设定集合的生存时间。</td></tr><tr><td>v</td><td>index version</td><td>索引的版本号。默认的索引版本取决于mongod创建索引时运行的版本。</td></tr><tr><td>weights</td><td>document</td><td>索引权重值，数值在1到99,999之间，表示该索引相对于其他索引字段的得分权重。</td></tr><tr><td>default_language</td><td>string</td><td>对于文本索引，该参数决定了停用词及词干和词器的规则的列表。默认为英语</td></tr><tr><td>language_override</td><td>string</td><td>对于文本索引，该参数指定了包含在文档中的字段名，语言覆盖默认的language，默认值为 language.</td></tr></tbody></table><p>索引需要设置正序或倒序:将articleid设为索引以倒序排列</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.createIndex({articleid: -1})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="复合索引" tabindex="-1"><a class="header-anchor" href="#复合索引"><span>复合索引</span></a></h4><p>在创建索引时可以指定多个字段</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.createIndex({userid: 1, articleid: -1})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="删除索引" tabindex="-1"><a class="header-anchor" href="#删除索引"><span>删除索引</span></a></h3><ul><li>index : 指定要删除的索引|。可以通过索引|名称或索引规范文档指定索引。若要删除文本索引.请指定索引名称。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.dropIndex(index)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>删除所有索引</strong> 删除所有用户创建的索引,mongodb自动创建的(_id)索引除外</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.dropIndexes()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>根据创建时的条件删(完全匹配的)</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.dropIndex({articleid: -1})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>根据索引名称删</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.dropIndex(&quot;userid_1_articleid_-1&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="查看集合索引的大小" tabindex="-1"><a class="header-anchor" href="#查看集合索引的大小"><span>查看集合索引的大小</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collections.totalIndexSize()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>传入非0会返回每个索引的大小</p><h3 id="索引的使用" tabindex="-1"><a class="header-anchor" href="#索引的使用"><span>索引的使用</span></a></h3><h4 id="执行计划" tabindex="-1"><a class="header-anchor" href="#执行计划"><span>执行计划</span></a></h4><p>分析查询性能（AnalyzeQueryPerformance）通常使用执行计划（解释计划、ExplainPlan）来查看查询的情况，如查询耗费的时间、是否基于索引查询等。 那么，通常，我们想知道，建立的索引是否有效，效果如何，都需要通过执行计划查看。</p><ul><li>options : 可选项</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.find(query,options).explain(options)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="副本集" tabindex="-1"><a class="header-anchor" href="#副本集"><span>副本集</span></a></h1><h3 id="简介" tabindex="-1"><a class="header-anchor" href="#简介"><span>简介</span></a></h3><p>MongoDB 中的副本集（Replica Set）是一组维护相同数据集的 mongod 服务。 副本集可提供<strong>冗余和高可用性</strong>，是所有生产部署的基础。</p><p>也可以说，副本集类似于有自动故障恢复功能的主从集群。通俗的讲就是用_多台机器进行同一数据的异步同步_，从而使多台机器拥有同一数据的多个副本，并且当主库当掉时在不需要用户干预的情况下自动切换其他备份服务器做主库。而且还可以<strong>利用副本服务器做只读服务器，实现读写分离，提高负载</strong>。</p><h4 id="冗余和数据可用性" tabindex="-1"><a class="header-anchor" href="#冗余和数据可用性"><span>冗余和数据可用性</span></a></h4><p>复制提供冗余并提高数据可用性。 通过在不同数据库服务器上提供多个数据副本，复制可提供一定级别的容错功能，以防止丢失单个数据库服务器。</p><p>在某些情况下，复制可以提供增加的读取性能，因为客户端可以将读取操作发送到不同的服务上， 在不同数据中心维护数据副本可以增加分布式应用程序的数据位置和可用性。 还可以为专用目的维护其他副本，例如灾难恢复，报告或备份。</p><h4 id="mongodb-中的复制" tabindex="-1"><a class="header-anchor" href="#mongodb-中的复制"><span>MongoDB 中的复制</span></a></h4><p>副本集是一组维护相同数据集的 mongod 实例。 副本集包含多个数据承载节点和可选的一个仲裁节点。 在承载数据的节点中，一个且仅一个成员被视为主节点，而其他节点被视为次要（从）节点。</p><p>主节点接收所有写操作。 副本集只能有一个主要能够确认具有 <code>{w：&quot;most&quot;}</code> 写入关注的写入; 虽然在某些情况下，另一个 mongod 实例可能暂时认为自己也是主要的。主要记录其操作日志中的数据集的所有 更改，即 oplog。</p><p>辅助(副本)节点复制主节点的oplog并将操作应用于其数据集，以使辅助节点的数据集反映主节点的数据 集。 如果主要人员不在，则符合条件的中学将举行选举以选出新的主要人员。</p><h4 id="主从复制和副本集区别" tabindex="-1"><a class="header-anchor" href="#主从复制和副本集区别"><span>主从复制和副本集区别</span></a></h4><p>主从集群和副本集最大的区别就是<strong>副本集没有固定的”主节点”</strong>；整个集群会选出一个”主节点”，当其挂掉后，又在剩下的从节点中选中其他节点为主节点，副本集总有一个活跃点 (主、primary) 和一个或多个备份节点 (从、secondary)</p><h3 id="副本集的三个角色" tabindex="-1"><a class="header-anchor" href="#副本集的三个角色"><span>副本集的三个角色</span></a></h3><blockquote><p>副本集有两种类型三种角色</p></blockquote><p>两种类型：</p><ul><li>主节点（Primary）类型：数据操作的主要连接点，<strong>可读写</strong></li><li>次要（辅助、从）节点（Secondary）类型：数据冗余备份节点，可以<strong>读或选举</strong></li></ul><p>三种角色：</p><ul><li>主要成员（Primary）：主要接收所有写操作。就是主节点</li><li>副本成员（Replicate）：从主节点通过复制操作以维护相同的数据集，即备份数据，<strong>不可写操作</strong>，但可以读操作（但需要配置）。是默认的一种从节点类型</li><li>仲裁者（Arbiter）：<strong>不保留任何数据的副本，只具有投票选举作用</strong>。当然也可以将仲裁服务器维护为副本集的一部分，即副本成员同时也可以是仲裁者。也是一种从节点类型。</li></ul><div class="language-mongod.conf line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="mongod.conf" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>systemLog:</span></span>
<span class="line"><span>    #MongoDB发送所有日志输出的目标指定为文件</span></span>
<span class="line"><span>    destination:file</span></span>
<span class="line"><span>    #mongod或mongos应向其发送所有诊断日志记录信息的日志文件的路径</span></span>
<span class="line"><span>    path: &quot;/D:/mongodb/replica_sets/myrs_27017/log/mongod.1og&quot;</span></span>
<span class="line"><span>    #当mongos或mongod实例重新启动时，mongos或mongod会将新条目附加到现有日志文件的末尾。</span></span>
<span class="line"><span>    logAppend:true</span></span>
<span class="line"><span>storage:</span></span>
<span class="line"><span>    #mongod实例存储其数据的目录。设置仅适用于mongod。</span></span>
<span class="line"><span>    dbpath: &quot;/D:/mongodb/replica_sets/myrs_27017/data/db&quot;</span></span>
<span class="line"><span>    journal: </span></span>
<span class="line"><span>    #启用或禁用持久性日志以确保数据文件保持有效和可恢复。</span></span>
<span class="line"><span>    enabled:true</span></span>
<span class="line"><span>processManagement:</span></span>
<span class="line"><span>    #启用在后台运行mongos或mongod进程的守护进程模式。</span></span>
<span class="line"><span>    fork:true</span></span>
<span class="line"><span>    #指定用于保存mongos或mongod进程的进程ID的文件位置，其中mongos或mongod将写入其PID</span></span>
<span class="line"><span>    pidFilePath: &quot;/D:/mongodb/replica_sets/myrs_27017/log/mongod.pid&quot;</span></span>
<span class="line"><span>net:</span></span>
<span class="line"><span>    #服务实例绑定所有IP，有副作用，副本集初始化的时候，节点名字会自动设置为本地域名，而不是ip</span></span>
<span class="line"><span>    #bindIpAll:true</span></span>
<span class="line"><span>    #服务实例绑定的IP</span></span>
<span class="line"><span>    bindIp: localhost,192.168.0.2</span></span>
<span class="line"><span>    #bindIp</span></span>
<span class="line"><span>    #绑定的端口</span></span>
<span class="line"><span>    port: 27017</span></span>
<span class="line"><span>replication: </span></span>
<span class="line"><span>    #副本集的名称</span></span>
<span class="line"><span>    replsetName:myrs</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="视图" tabindex="-1"><a class="header-anchor" href="#视图"><span>视图</span></a></h1><p>视图是只读的</p><h4 id="创建视图" tabindex="-1"><a class="header-anchor" href="#创建视图"><span>创建视图</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.createView(&quot;名称&quot;,&quot;数据来源的集合&quot;,聚合的数据)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="查询视图" tabindex="-1"><a class="header-anchor" href="#查询视图"><span>查询视图</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.find()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>视图上的 <code>find()</code>方法不支持如下projection操作:</p><ul><li><code>$</code></li><li><code>$elemMatch</code></li><li><code>$slice</code></li><li><code>$meta</code> 不能重命名视图</li></ul><h3 id="删除视图" tabindex="-1"><a class="header-anchor" href="#删除视图"><span>删除视图</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.drop()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,60)]))}const p=e(d,[["render",l]]),o=JSON.parse('{"path":"/tools/mongodb/2/","title":"2 优化","lang":"zh-CN","frontmatter":{"title":"2 优化","createTime":"2025/06/23 09:32:20","permalink":"/tools/mongodb/2/"},"readingTime":{"minutes":6.46,"words":1937},"git":{"createdTime":1750599657000,"updatedTime":1750644294000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":2,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/MongoDB/2 优化.md","headers":[]}');export{p as comp,o as data};
